(window.webpackJsonp=window.webpackJsonp||[]).push([[258],{544:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * @param {string[]} req_skills\\n * @param {string[][]} people\\n * @return {number[]}\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> smallestSufficientTeam = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">req_skills, people</span>) </span>{\\n\\n  <span class=\\"hljs-keyword\\">let</span> skill_len=req_skills.length\\n  \\n  <span class=\\"hljs-comment\\">// convert people[i] to the index of req_skills</span>\\n  <span class=\\"hljs-keyword\\">let</span> id_people=[]\\n  <span class=\\"hljs-keyword\\">let</span> hash={}\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;skill_len;i++){\\n    hash[req_skills[i]]=i\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;people.length;i++){\\n    id_people[i]=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;people[i].length;j++){\\n      id_people[i][j]=hash[people[i][j]]\\n    }\\n  }\\n\\n  <span class=\\"hljs-comment\\">// filter the people which is impossible to choose</span>\\n  <span class=\\"hljs-keyword\\">let</span> skip={}\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;id_people.length;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(skip[i])<span class=\\"hljs-keyword\\">continue</span>\\n    <span class=\\"hljs-keyword\\">let</span> skills=<span class=\\"hljs-built_in\\">Array</span>(skill_len).fill(<span class=\\"hljs-number\\">0</span>)\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;id_people[i].length;j++){\\n      <span class=\\"hljs-keyword\\">let</span> curId=id_people[i][j]\\n      skills[curId]++\\n    }\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> k=i+<span class=\\"hljs-number\\">1</span>;k&lt;id_people.length;k++){\\n      <span class=\\"hljs-keyword\\">if</span>(skip[k])<span class=\\"hljs-keyword\\">continue</span>\\n      <span class=\\"hljs-keyword\\">let</span> needSkip=<span class=\\"hljs-literal\\">true</span>\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> l=<span class=\\"hljs-number\\">0</span>;l&lt;id_people[k].length;l++){\\n        <span class=\\"hljs-keyword\\">let</span> id=id_people[k][l]\\n        <span class=\\"hljs-keyword\\">if</span>(skills[id]===<span class=\\"hljs-number\\">0</span>){\\n          needSkip=<span class=\\"hljs-literal\\">false</span>\\n          <span class=\\"hljs-keyword\\">break</span>\\n        }\\n      }\\n      <span class=\\"hljs-keyword\\">if</span>(needSkip){\\n        skip[k]=<span class=\\"hljs-literal\\">true</span>\\n      }\\n    }\\n  }\\n\\n  <span class=\\"hljs-comment\\">// slim the people, so  slim_people are the people who can be choose</span>\\n  <span class=\\"hljs-keyword\\">let</span> slim_people=[]\\n  <span class=\\"hljs-keyword\\">let</span> idHash={}\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;id_people.length;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(skip[i])<span class=\\"hljs-keyword\\">continue</span>\\n    idHash[slim_people.length]=i\\n    slim_people.push(id_people[i])\\n  }\\n\\n  <span class=\\"hljs-comment\\">// backtracking</span>\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-literal\\">Infinity</span>\\n  <span class=\\"hljs-keyword\\">let</span> peopleChoose=<span class=\\"hljs-built_in\\">Array</span>(slim_people).fill(<span class=\\"hljs-literal\\">false</span>)\\n  <span class=\\"hljs-keyword\\">let</span> ans=<span class=\\"hljs-literal\\">null</span>\\n  <span class=\\"hljs-keyword\\">let</span> team=<span class=\\"hljs-built_in\\">Array</span>(skill_len).fill(<span class=\\"hljs-number\\">0</span>)\\n\\n  backtrack(<span class=\\"hljs-number\\">0</span>,team,<span class=\\"hljs-number\\">0</span>,peopleChoose)\\n\\n  <span class=\\"hljs-keyword\\">return</span> ans\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">backtrack</span>(<span class=\\"hljs-params\\">id,team,count,peopleChoose</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(count&gt;=res)<span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">let</span> isSufficient=<span class=\\"hljs-literal\\">true</span>\\n    <span class=\\"hljs-comment\\">// check if is a sufficient team</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;team.length;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(team[i]===<span class=\\"hljs-number\\">0</span>){\\n        isSufficient=<span class=\\"hljs-literal\\">false</span>\\n      }\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(isSufficient){\\n      <span class=\\"hljs-comment\\">// save which people wo have choose</span>\\n      res=count\\n      <span class=\\"hljs-keyword\\">let</span> _res_=[]\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;peopleChoose.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(peopleChoose[i])_res_.push(idHash[i])\\n      }\\n      ans=_res_\\n      <span class=\\"hljs-keyword\\">return</span>\\n    }\\n    <span class=\\"hljs-comment\\">// we check every people and try to make a sufficient team</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> k=id;k&lt;slim_people.length;k++){\\n      <span class=\\"hljs-keyword\\">let</span> curPeopleSkills=slim_people[k]\\n      curPeopleSkills.forEach(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">skillId</span>=&gt;</span>team[skillId]++)\\n      peopleChoose[k]=<span class=\\"hljs-literal\\">true</span>\\n      backtrack(k+<span class=\\"hljs-number\\">1</span>,team,count+<span class=\\"hljs-number\\">1</span>,peopleChoose)\\n      peopleChoose[k]=<span class=\\"hljs-literal\\">false</span>\\n      curPeopleSkills.forEach(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">skillId</span>=&gt;</span>team[skillId]--)\\n    }\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"smallest-sufficient-team","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<ol>\\n<li>\\n<p>\u5c06<code>people</code>\u7684\u5185\u5bb9\u8f6c\u6362\u4e3a<code>index</code>\u3002</p>\\n<p>\u4f8b\u5982\uff1a</p>\\n<p><code>req_skills = [&quot;java&quot;,&quot;nodejs&quot;,&quot;reactjs&quot;]</code></p>\\n<p>\u8f6c\u6362\u524d:</p>\\n<p><code>people = [[&quot;java&quot;],[&quot;nodejs&quot;],[&quot;nodejs&quot;,&quot;reactjs&quot;]]</code></p>\\n<p>\u8f6c\u6362\u540e:</p>\\n<p><code>id_people=[[0],[1],[1,2]]</code></p>\\n</li>\\n<li>\\n<p>\u8fc7\u6ee4\u6389\u90a3\u4e48\u4e0d\u53ef\u80fd\u88ab\u9009\u4e2d\u7684\u4eba\u3002</p>\\n<p>\u4f8b\u5982\uff1a</p>\\n<p><code>id_people=[[0],[1],[1,2]]</code></p>\\n<p><code>id_people[1]</code>\u662f\u4e0d\u53ef\u80fd\u88ab\u9009\u4e2d\u7684\uff0c\u56e0\u4e3a<code>id_people[2]</code>\u5305\u542b\u4e86\u4ed6\u6240\u6709\u7684\u6280\u80fd\u3002</p>\\n<p>\u8fc7\u6ee4\u540e\uff0c<code>slim_people=[[0],[1,2]]</code>.</p>\\n<p>\u8fd8\u9700\u8981\u4e00\u4e2a<code>idHash</code>\uff0c\u8fd9\u662f\u4e00\u4e2a<code>Ojbect</code>\uff0c\u4fdd\u5b58<code>slim_people</code>\u548c<code>id_people</code>\u7684\u7d22\u5f15\u5173\u7cfb\u3002</p>\\n</li>\\n<li>\\n<p>\u56de\u6eaf\uff0c\u5728\u56de\u6eaf\u4e2d\uff0c\u5bf9\u6bcf\u4e00\u4e2a\u4eba\u5c1d\u8bd5\u6dfb\u52a0\u8fdb\u961f\u4f0d\uff0c\u5e76\u4e14\u68c0\u67e5\u5f53\u524d\u961f\u4f0d\u662f\u5426\u6ee1\u8db3<code>\u5fc5\u8981\u56e2\u961f</code>\u3002</p>\\n<p>\u5982\u679c\u6ee1\u8db3\uff0c\u68c0\u67e5\u5f53\u524d\u961f\u4f0d\u4eba\u6570\u662f\u5426\u66f4\u5c0f\uff0c\u5982\u679c\u66f4\u5c0f\uff0c\u4fdd\u5b58\u5f53\u524d\u961f\u4f0d\u7684\u7d22\u5f15\u3002</p>\\n</li>\\n</ol>\\n","content":"<p>\u4f5c\u4e3a\u9879\u76ee\u7ecf\u7406\uff0c\u4f60\u89c4\u5212\u4e86\u4e00\u4efd\u9700\u6c42\u7684\u6280\u80fd\u6e05\u5355&nbsp;<code>req_skills</code>\uff0c\u5e76\u6253\u7b97\u4ece\u5907\u9009\u4eba\u5458\u540d\u5355&nbsp;<code>people</code>&nbsp;\u4e2d\u9009\u51fa\u4e9b\u4eba\u7ec4\u6210\u4e00\u4e2a\u300c\u5fc5\u8981\u56e2\u961f\u300d\uff08 \u7f16\u53f7\u4e3a&nbsp;<code>i</code>&nbsp;\u7684\u5907\u9009\u4eba\u5458&nbsp;<code>people[i]</code>&nbsp;\u542b\u6709\u4e00\u4efd\u8be5\u5907\u9009\u4eba\u5458\u638c\u63e1\u7684\u6280\u80fd\u5217\u8868\uff09\u3002</p>\\n\\n<p>\u6240\u8c13\u300c\u5fc5\u8981\u56e2\u961f\u300d\uff0c\u5c31\u662f\u5728\u8fd9\u4e2a\u56e2\u961f\u4e2d\uff0c\u5bf9\u4e8e\u6240\u9700\u6c42\u7684\u6280\u80fd\u5217\u8868&nbsp;<code>req_skills</code> \u4e2d\u5217\u51fa\u7684\u6bcf\u9879\u6280\u80fd\uff0c\u56e2\u961f\u4e2d\u81f3\u5c11\u6709\u4e00\u540d\u6210\u5458\u5df2\u7ecf\u638c\u63e1\u3002</p>\\n\\n<p>\u6211\u4eec\u53ef\u4ee5\u7528\u6bcf\u4e2a\u4eba\u7684\u7f16\u53f7\u6765\u8868\u793a\u56e2\u961f\u4e2d\u7684\u6210\u5458\uff1a\u4f8b\u5982\uff0c\u56e2\u961f&nbsp;<code>team = [0, 1, 3]</code>&nbsp;\u8868\u793a\u638c\u63e1\u6280\u80fd\u5206\u522b\u4e3a&nbsp;<code>people[0]</code>\uff0c<code>people[1]</code>\uff0c\u548c&nbsp;<code>people[3]</code>&nbsp;\u7684\u5907\u9009\u4eba\u5458\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de <strong>\u4efb\u4e00</strong>&nbsp;\u89c4\u6a21\u6700\u5c0f\u7684\u5fc5\u8981\u56e2\u961f\uff0c\u56e2\u961f\u6210\u5458\u7528\u4eba\u5458\u7f16\u53f7\u8868\u793a\u3002\u4f60\u53ef\u4ee5\u6309\u4efb\u610f\u987a\u5e8f\u8fd4\u56de\u7b54\u6848\uff0c\u672c\u9898\u4fdd\u8bc1\u7b54\u6848\u5b58\u5728\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>req_skills = [&quot;java&quot;,&quot;nodejs&quot;,&quot;reactjs&quot;], people = [[&quot;java&quot;],[&quot;nodejs&quot;],[&quot;nodejs&quot;,&quot;reactjs&quot;]]\\n<strong>\u8f93\u51fa\uff1a</strong>[0,2]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b&nbsp;2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>req_skills = [&quot;algorithms&quot;,&quot;math&quot;,&quot;java&quot;,&quot;reactjs&quot;,&quot;csharp&quot;,&quot;aws&quot;], people = [[&quot;algorithms&quot;,&quot;math&quot;,&quot;java&quot;],[&quot;algorithms&quot;,&quot;math&quot;,&quot;reactjs&quot;],[&quot;java&quot;,&quot;csharp&quot;,&quot;aws&quot;],[&quot;reactjs&quot;,&quot;csharp&quot;],[&quot;csharp&quot;,&quot;math&quot;],[&quot;aws&quot;,&quot;java&quot;]]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,2]\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= req_skills.length &lt;= 16</code></li>\\n\\t<li><code>1 &lt;= people.length &lt;= 60</code></li>\\n\\t<li><code>1 &lt;= people[i].length, req_skills[i].length, people[i][j].length&nbsp;&lt;= 16</code></li>\\n\\t<li><code>req_skills</code>&nbsp;\u548c&nbsp;<code>people[i]</code>&nbsp;\u4e2d\u7684\u5143\u7d20\u5206\u522b\u5404\u4e0d\u76f8\u540c</li>\\n\\t<li><code>req_skills[i][j], people[i][j][k]</code>&nbsp;\u90fd\u7531\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd\u7ec4\u6210</li>\\n\\t<li>\u672c\u9898\u4fdd\u8bc1\u300c\u5fc5\u8981\u56e2\u961f\u300d\u4e00\u5b9a\u5b58\u5728</li>\\n</ul>\\n"}')}}]);